#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        uint32_t a, and_all = 0xFFFFFFFFu, or_all = 0;
        for(int i=0;i<N;i++){
            scanf("%u", &a);
            and_all &= a;
            or_all  |= a;
        }
        uint32_t X = and_all;
        uint32_t minOR = or_all ^ and_all;
        printf("%u %u\n", X, minOR);
    }
    return 0;
}

