const T = Number(input[idx++]);
let output = [];
for (let t = 0; t < T; t++) {
  const N = Number(input[idx++]);
  let andAll = 0xFFFFFFFF;
  let orAll = 0;
  for (let i = 0; i < N; i++) {
    const a = Number(input[idx++]);
    andAll &= a;
    orAll |= a;
  }
  const X = andAll >>> 0; // ensure unsigned
  const minOR = (orAll ^ andAll) >>> 0;
  output.push(`${X} ${minOR}`);
}
console.log(output.join('\n'));

